import { useEffect, useState } from "react";
import api from "../api/axios";
import "./styles/Admin.css";

function AdminStudents() {
  const [students, setStudents] = useState([]);

  useEffect(() => {
    fetchStudents();
  }, []);

  const fetchStudents = async () => {
    const res = await api.get("/admin/students");
    setStudents(res.data);
  };

  const toggleBlock = async (id) => {
    await api.put(`/admin/students/${id}/toggle`);
    fetchStudents();
  };

  const deleteStudent = async (id) => {
    if (!window.confirm("Remove this student?")) return;
    await api.delete(`/admin/students/${id}`);
    fetchStudents();
  };

  return (
    <div className="admin-page">
      <h1 className="admin-title">Manage Students</h1>

      <div className="admin-table">
        <div className="table-head">
          <span>Name</span>
          <span>Email</span>
          <span>Joined</span>
          <span>Status</span>
          <span>Actions</span>
        </div>

        {students.map((s) => (
          <div key={s._id} className="table-row">
            <span>{s.name}</span>
            <span>{s.email}</span>
            <span>{new Date(s.createdAt).toLocaleDateString()}</span>

            <span className={s.isBlocked ? "blocked" : "active"}>
              {s.isBlocked ? "Blocked" : "Active"}
            </span>

            <div className="actions">
              <button onClick={() => toggleBlock(s._id)}>
                {s.isBlocked ? "Unblock" : "Block"}
              </button>

              <button className="danger" onClick={() => deleteStudent(s._id)}>
                Remove
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default AdminStudents;
